import json, os
p='logs/sweeps/action_sweep.json'
with open(p) as f: data=json.load(f)
print('type', type(data), 'len', len(data) if hasattr(data,'__len__') else None)
if isinstance(data, dict):
    print('keys', list(data.keys())[:20])
    # infer records
    for k,v in data.items():
        print('first key', k, 'vtype', type(v), 'vlen', len(v) if hasattr(v,'__len__') else None)
        if isinstance(v, list) and v:
            print('sample', v[0])
        elif isinstance(v, dict):
            print('subkeys', list(v.keys())[:10])
            for kk,vv in list(v.items())[:1]: print('subsample', kk, vv)
        break
else:
    print('sample', data[0] if data else None)

bars={
'h1hand-walk-v0':700,'h1hand-stand-v0':800,'h1hand-run-v0':700,'h1hand-sit_simple-v0':750,
'h1hand-balance_simple-v0':800,'h1hand-reach-v0':12000,'h1hand-push-v0':700,'h1hand-pole-v0':700,
'h1hand-door-v0':600,'h1hand-package-v0':1500}
records=[]
if isinstance(data, list):
    records=data
elif isinstance(data, dict):
    for task, val in data.items():
        if isinstance(val, list):
            for r in val:
                rr=dict(r); rr.setdefault('task_id', task); records.append(rr)
        elif isinstance(val, dict):
            for kind, vv in val.items():
                rr={'task_id':task,'kind':kind}
                if isinstance(vv, dict): rr.update(vv)
                else: rr['rewards']=vv
                records.append(rr)
print('records', len(records))
for task in ['h1hand-sit_simple-v0','h1hand-pole-v0','h1hand-door-v0','h1hand-push-v0','h1hand-walk-v0','h1hand-stand-v0']:
    cand=[]
    for r in records:
        tid=r.get('task_id') or r.get('task')
        if tid!=task: continue
        kind=r.get('kind') or r.get('policy') or r.get('name') or r.get('action')
        rewards=r.get('rewards') or r.get('episode_rewards') or r.get('returns') or r.get('reward')
        if rewards is None: continue
        if not isinstance(rewards, list): continue
        cand.append((kind, [float(x) for x in rewards]))
    if not cand:
        continue
    bar=bars[task]
    n=max(len(rs) for _,rs in cand)
    print('\nTASK', task, 'candidates', len(cand), 'bar', bar)
    total_succ=0
    mapping={}
    for seed in range(n):
        best=None
        for kind,rs in cand:
            if seed>=len(rs): continue
            tup=(rs[seed], kind)
            if best is None or tup[0]>best[0]: best=tup
        if best:
            succ=best[0]>=bar
            total_succ+=int(succ)
            mapping[seed]=(best[1], round(best[0],1), int(succ))
    print('best_per_seed_successes_on_swept', total_succ, '/', n)
    print(mapping)
